def compute_score() -> tuple[str, float]:
    expected_title = 'building analysis methods'.strip().lower()
    added_slides = ppt_diff.added_slides
    if len(added_slides) != 1:
        return "Can't check title: not exactly one new slide.", 0.0
    title = (added_slides[0].title or '').strip().lower()
    if title == expected_title:
        return "Title matches exactly.", 1.0
    if expected_title in title:
        return "Title contains expected text, but has extra content.", 0.7
    return f"Title '{title}' does not match expected '{expected_title}'.", 0.0

def compute_score() -> tuple[str, float]:
